<!doctype html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Savorly Operations Portal</title><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=Fraunces:wght@600;700&display=swap" rel="stylesheet"><link rel="stylesheet" href="../assets/css/admin.css"><link rel="stylesheet" href="../assets/css/admin-views.css"><link rel="stylesheet" href="../assets/css/password-toggle.css"><link rel="stylesheet" href="../assets/css/admin-responsive.css"><link rel="stylesheet" href="../assets/css/admin-responsive-polish.css"></head><body>
<section class="login-screen" id="staff-login"><div class="login-art"><a class="brand" href="../"><span>S</span>Savorly</a><div><p class="eyebrow">OPERATIONS PORTAL</p><h1>Keep every order<br><em>moving.</em></h1><p>A focused workspace for kitchen staff and restaurant administrators.</p></div><small>Customer? <a href="../">Return to the ordering website</a></small></div><div class="login-panel"><form id="staff-login-form"><div class="mobile-brand"><span>S</span>Savorly</div><p class="eyebrow">AUTHORIZED ACCESS</p><h2>Admin & Staff login</h2><p class="muted">Use your restaurant account to access order management.</p><label>Email address<input name="email" type="email" required autocomplete="username" placeholder="name@savorly.local"></label><label>Password<input name="password" type="password" required autocomplete="current-password" placeholder="Enter your password"></label><button type="submit">Sign in to portal <b>-&gt;</b></button><p class="login-error" role="alert"></p><div class="demo-box"><strong>Demo accounts</strong><span>Admin: admin@savorly.local / Admin@123</span><span>Staff: staff@savorly.local / Staff@123</span></div></form></div></section>
<div class="portal hidden" id="staff-portal"><aside class="sidebar"><a class="brand" href="./" title="Savorly Operations"><span>S</span>Savorly</a><div class="portal-label">OPERATIONS</div><nav><button class="active" data-portal-tab="dashboard" title="Dashboard"><i>DB</i> Dashboard</button><button data-portal-tab="orders" title="Orders"><i>OR</i> Orders</button><button data-portal-tab="products" title="Menu Products"><i>MP</i> Menu Products</button><button class="admin-only" data-portal-tab="staff" title="Staff Accounts"><i>SA</i> Staff</button><a href="../" target="_blank" title="Customer site"><i>CS</i> Customer site</a></nav><div class="staff-card"><span class="staff-avatar">A</span><div><strong class="staff-name">Staff User</strong><small class="staff-role">STAFF</small></div><button class="logout" title="Log out">Out</button></div></aside><main><header><div><p class="eyebrow portal-eyebrow">RESTAURANT OVERVIEW</p><h1><span class="portal-heading">Good day</span>, <span class="welcome-name">team</span>.</h1></div><div class="live-indicator"><span></span> Live orders</div></header>
<section class="portal-view dashboard-view" data-portal-view="dashboard"><section class="stats"><article><div class="stat-icon green">TO</div><div><small>Total orders</small><strong id="total-orders">0</strong><p>All-time orders</p></div></article><article class="admin-only"><div class="stat-icon orange">PHP</div><div><small>Today's revenue</small><strong id="today-revenue">PHP 0</strong><p>Delivered orders only</p></div></article><article><div class="stat-icon gold">AO</div><div><small>Active orders</small><strong id="active-orders">0</strong><p>Needs attention</p></div></article><article><div class="stat-icon blue">CU</div><div><small>Customers</small><strong id="customers">0</strong><p>Unique customers</p></div></article></section><section class="revenue-panel admin-only"><div class="revenue-heading"><div><p class="eyebrow">SALES ANALYTICS</p><h2>Revenue sales</h2><span>Delivered orders in Philippine pesos</span></div><div class="revenue-actions"><div class="period-tabs"><button class="active" data-revenue-period="daily">Daily</button><button data-revenue-period="weekly">Weekly</button><button data-revenue-period="monthly">Monthly</button></div><button class="download-revenue" type="button">Download PDF</button></div></div><div class="revenue-summary"><div><small>Period revenue</small><strong id="period-revenue">PHP 0</strong></div><div><small>Delivered orders</small><strong id="period-orders">0</strong></div><div><small>Average order</small><strong id="average-order">PHP 0</strong></div></div><div class="revenue-chart" role="img" aria-label="Delivered order revenue bar chart"></div><div class="chart-empty hidden">No delivered sales data for this period.</div></section><div class="dashboard-note"><strong>Restaurant overview</strong><p>Use the Orders tab to review incoming orders and update their progress.</p><button data-open-orders>Open order management -&gt;</button></div></section>
<section class="portal-view orders-view hidden" data-portal-view="orders"><section class="orders-panel"><div class="panel-heading"><div><h2>Order management</h2><p>Click a customer to view their complete profile, order, and note.</p></div><label class="search">Search <input id="order-search" placeholder="Search orders or customers"></label></div><div class="filter-tabs"><button class="active" data-filter="All">All</button><button data-filter="Order placed">New</button><button data-filter="Preparing">Preparing</button><button data-filter="Out for delivery">Delivery</button><button data-filter="Delivered">Completed</button></div><div class="table-wrap"><table><thead><tr><th>ORDER</th><th>CUSTOMER</th><th>ITEMS</th><th>TOTAL</th><th>STATUS</th><th>PLACED</th></tr></thead><tbody id="orders-body"></tbody></table><div class="empty hidden"><h3>No matching orders</h3><p>Orders will appear here as customers place them.</p></div></div></section></section>
<section class="portal-view products-view hidden" data-portal-view="products"><section class="products-panel"><div class="panel-heading"><div><p class="eyebrow">MENU MANAGEMENT</p><h2>Food products</h2><p>Create products, update details, pricing, categories, and availability.</p></div><div class="product-heading-actions"><label class="search">Search <input id="product-search" placeholder="Search products or categories"></label><button class="add-product" type="button">Add product</button></div></div><div class="products-table-wrap"><table class="products-table"><thead><tr><th>PRODUCT</th><th>CATEGORY</th><th>NOTES</th><th>PRICE</th><th>STATUS</th><th>ACTION</th></tr></thead><tbody id="products-body"></tbody></table><div class="products-empty hidden"><h3>No products found</h3><p>Add a product or change your search.</p></div></div></section></section>
<section class="portal-view staff-view hidden admin-only" data-portal-view="staff"><section class="staff-panel"><div class="panel-heading"><div><p class="eyebrow">TEAM MANAGEMENT</p><h2>Staff accounts</h2><p>Create staff accounts, assign Staff or Manager roles, and control login access.</p></div><div class="staff-heading-actions"><label class="search">Search <input id="staff-search" placeholder="Search staff or email"></label><button class="add-staff" type="button">Add staff</button></div></div><div class="staff-table-wrap"><table class="staff-table"><thead><tr><th>STAFF</th><th>ROLE</th><th>STATUS</th><th>CREATED</th><th>ACTION</th></tr></thead><tbody id="staff-body"></tbody></table><div class="staff-empty hidden"><h3>No staff accounts found</h3><p>Create a staff account to give kitchen users portal access.</p></div></div></section></section></main></div>
<div class="detail-backdrop hidden"></div><section class="customer-detail-modal hidden" role="dialog" aria-modal="true" aria-labelledby="detail-title"><button class="detail-close" type="button" aria-label="Close">x</button><header class="detail-header"><span class="detail-avatar">C</span><div><p class="eyebrow">CUSTOMER & ORDER DETAILS</p><h2 id="detail-title">Customer name</h2><span class="detail-username">@username</span></div></header><div class="detail-contact"><article><small>Email</small><strong class="detail-email">-</strong></article><article><small>Phone</small><strong class="detail-phone">-</strong></article><article><small>Saved address</small><strong class="detail-saved-address">-</strong></article></div><div class="detail-order-heading"><div><small>ORDER</small><strong class="detail-order-number">#000000</strong></div><span class="detail-status">Order placed</span></div><div class="detail-grid"><article><small>Placed</small><strong class="detail-created">-</strong></article><article><small>Payment</small><strong class="detail-payment">-</strong></article><article><small>Delivery phone</small><strong class="detail-order-phone">-</strong></article><article><small>Total</small><strong class="detail-total">-</strong></article></div><article class="detail-address-block"><small>Delivery destination</small><p class="detail-delivery-address">-</p></article><article class="customer-note"><small>CUSTOMER NOTE</small><p class="detail-note">No special instructions.</p></article><div class="detail-columns"><div><h3>Order items</h3><div class="detail-items"></div></div><div><h3>Status history</h3><div class="detail-history"></div></div></div></section>
<div class="product-backdrop hidden"></div><section class="product-modal hidden" role="dialog" aria-modal="true" aria-labelledby="product-modal-title"><button class="product-close" type="button" aria-label="Close">x</button><p class="eyebrow">MENU PRODUCT</p><h2 id="product-modal-title">Add new product</h2><p class="product-modal-copy">Enter the food product information below.</p><form id="product-form" enctype="multipart/form-data"><input name="id" type="hidden"><div class="product-form-row"><label>Product name<input name="name" required maxlength="140" placeholder="Classic Burger"></label><label>Category<input name="category" required maxlength="60" placeholder="Burgers" list="category-list"><datalist id="category-list"><option>Pasta</option><option>Bowls</option><option>Burgers</option><option>Pizza</option><option>Sides</option><option>Drinks</option><option>Desserts</option><option>Salads</option></datalist></label></div><label>Notes / Description<textarea name="description" required maxlength="255" placeholder="Ingredients, preparation, and product notes"></textarea></label><label>Price (PHP)<input name="price" type="number" required min="1" step="0.01" placeholder="199.00"></label><fieldset class="badge-options"><legend>Badge (optional)</legend><label><input name="badge" type="radio" value="" checked><span>None</span></label><label><input name="badge" type="radio" value="NEW"><span>New</span></label><label><input name="badge" type="radio" value="POPULAR"><span>Popular</span></label><label><input name="badge" type="radio" value="BESTSELLER"><span>Bestseller</span></label></fieldset><label class="product-image-field">Food image (JPG, PNG, or WebP; maximum 5 MB)<input name="image" type="file" accept="image/jpeg,image/png,image/webp"><span class="product-image-preview"><b>No image selected</b><small>Choose a clear photo of the food product.</small></span></label><button class="save-product" type="submit">Save product</button></form></section>
<div class="staff-backdrop hidden"></div><section class="staff-modal hidden" role="dialog" aria-modal="true" aria-labelledby="staff-modal-title"><button class="staff-close" type="button" aria-label="Close">x</button><p class="eyebrow">STAFF ACCOUNT</p><h2 id="staff-modal-title">Add staff account</h2><p class="staff-modal-copy">Only administrators can manage staff access.</p><form id="staff-form"><input name="id" type="hidden"><label>Full name<input name="name" required maxlength="120" placeholder="Kitchen Staff"></label><label>Email address<input name="email" type="email" required maxlength="190" placeholder="staff@savorly.local"></label><label>Password<input name="password" type="password" minlength="6" placeholder="Leave blank when editing"></label><fieldset class="staff-role-options"><legend>Role</legend><label><input name="role" type="radio" value="staff" checked><span>Staff</span></label><label><input name="role" type="radio" value="manager"><span>Manager</span></label></fieldset><label class="staff-active-check"><input name="isActive" type="checkbox" checked><span>Active account</span></label><button class="save-staff" type="submit">Save staff</button></form></section>
<div class="toast" role="status"></div><script src="../assets/js/password-toggle.js"></script><script src="../assets/js/admin.js"></script></body></html>
